formulas.expression:
/* Critical: 1 business day */
CASE(
    WEEKDAY(TODAY()),
    /* Sunday (1) - add 1 day to get to Monday */
    1, TODAY() + 1,
    /* Monday (2) - add 1 day to get to Tuesday */
    2, TODAY() + 1,
    /* Tuesday (3) - add 1 day to get to Wednesday */
    3, TODAY() + 1,
    /* Wednesday (4) - add 1 day to get to Thursday */
    4, TODAY() + 1,
    /* Thursday (5) - add 1 day to get to Friday */
    5, TODAY() + 1,
    /* Friday (6) - add 3 days to get to Monday */
    6, TODAY() + 3,
    /* Saturday (7) - add 2 days to get to Monday */
    7, TODAY() + 2,
    /* Default */
    TODAY() + 1
)

/* High: 3 business days */
CASE(
    WEEKDAY(TODAY()),
    /* Sunday (1) - add 3 days to get to Wednesday */
    1, TODAY() + 3,
    /* Monday (2) - add 3 days to get to Thursday */
    2, TODAY() + 3,
    /* Tuesday (3) - add 3 days to get to Friday */
    3, TODAY() + 3,
    /* Wednesday (4) - add 5 days to skip weekend, get to Monday */
    4, TODAY() + 5,
    /* Thursday (5) - add 5 days to skip weekend, get to Tuesday */
    5, TODAY() + 5,
    /* Friday (6) - add 5 days to skip weekend, get to Wednesday */
    6, TODAY() + 5,
    /* Saturday (7) - add 4 days to get to Wednesday */
    7, TODAY() + 4,
    /* Default */
    TODAY() + 3
)

/* Low: 7 business days */
CASE(
    WEEKDAY(TODAY()),
    /* Sunday (1) - add 7 days to get to Sunday, then +1 to Monday */
    1, TODAY() + 8,
    /* Monday (2) - add 9 days to skip weekend, get to Wednesday */
    2, TODAY() + 9,
    /* Tuesday (3) - add 9 days to skip weekend, get to Thursday */
    3, TODAY() + 9,
    /* Wednesday (4) - add 9 days to skip weekend, get to Friday */
    4, TODAY() + 9,
    /* Thursday (5) - add 9 days to skip weekend, get to Monday */
    5, TODAY() + 11,
    /* Friday (6) - add 9 days to skip weekend, get to Tuesday */
    6, TODAY() + 11,
    /* Saturday (7) - add 8 days to get to Sunday, then +1 to Monday */
    7, TODAY() + 9,
    /* Default */
    TODAY() + 7
)

/* Medium: 5 business days */
CASE(
    WEEKDAY(TODAY()),
    /* Sunday (1) - add 5 days to get to Friday */
    1, TODAY() + 5,
    /* Monday (2) - add 7 days to skip weekend, get to Monday */
    2, TODAY() + 7,
    /* Tuesday (3) - add 7 days to skip weekend, get to Tuesday */
    3, TODAY() + 7,
    /* Wednesday (4) - add 7 days to skip weekend, get to Wednesday */
    4, TODAY() + 7,
    /* Thursday (5) - add 7 days to skip weekend, get to Thursday */
    5, TODAY() + 7,
    /* Friday (6) - add 7 days to skip weekend, get to Friday */
    6, TODAY() + 7,
    /* Saturday (7) - add 6 days to get to Friday */
    7, TODAY() + 6,
    /* Default */
    TODAY() + 5
)
